CREATE TABLE IF NOT EXISTS person_dossiers (
    dossier_id TEXT PRIMARY KEY,
    person_id TEXT NOT NULL UNIQUE REFERENCES persons(person_id),
    sequence_no INTEGER NOT NULL,
    file_path TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'foundational_v0.1',
    evidence_policy TEXT NOT NULL,
    generated_from_migration TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_person_dossiers_sequence ON person_dossiers(sequence_no);

